module RefModule(CLK, RESET, SIN, Q);
input CLK, RESET, SIN;
output [2:0] Q;
reg [2:0] Q;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge RESET or posedge dbg_halt) begin
    if (RESET)
        Q <= 3'b000;
    else
        Q <= {Q[1:0], SIN};
end

endmodule
